using Microsoft.AspNetCore.Mvc;

public class ReportController : Controller
{
    [HttpPost]
    public IActionResult ExportReport()
    {
        var data = GenerateReport();

        // In ASP.NET Core, return a FileResult instead of writing to Response directly.
        // No Response.End() needed — returning terminates the action naturally.
        return File(
            System.Text.Encoding.UTF8.GetBytes(data),
            "text/csv",
            "report.csv"
        );
    }

    [HttpPost]
    public IActionResult RedirectAfterProcess()
    {
        if (!User.Identity?.IsAuthenticated ?? true)
        {
            // RedirectResult terminates the action via return — no Thread.Abort.
            return Redirect("/login");
        }

        try
        {
            ProcessRequest();
            return Redirect("/success");
        }
        // No catch (ThreadAbortException) needed — Redirect() doesn't throw.
        catch (Exception ex)
        {
            LogError(ex);
            return Redirect("/error");
        }
    }
}
